import type React from 'react';
import type { TestComponentProps } from '../../types/test-component';
export type BasicAlignment = 'left' | 'center' | 'right';
export interface DropdownMenuProps<PT = HTMLElement> extends TestComponentProps {
    /** Выравнивание по горизонтали */
    align?: BasicAlignment;
    /** id корневого тега страницы */
    applicationRootElementID?: string;
    /** Пользовательский класс */
    className?: string;
    /** Пользовательский класс для компонента Positioner */
    positionerClassName?: string;
    /** id корневого тега компонента */
    dropdownElementID?: string;
    /**
     * Внешний отступ по горизонтали.
     * @default 0px
     * */
    horizontalOffset?: number;
    /** Внешний отступ по вертикали.
     * @default 8px
     * */
    verticalOffset?: number;
    onOpen?: () => void;
    /** Обработчик события клика вне границ компонента */
    onOutsideClick?: () => void;
    onBlur?: React.FocusEventHandler<PT>;
    /** Родительский элемент */
    targetElement: React.RefObject<PT>;
    /**
     * Флаг. Указывает на возможность появления скролла внутри DropdownMenu.
     * Учитывается при вычислении позиции.
     * Н-р: Для DatePicker значение должно быть false, чтобы не было скролла внутри DropdownMenu.
     * @default true
     * */
    scrollable?: boolean;
    /**
     * Минимальная высота до которой может сжаться DropdownMenu.
     * Учитывается при вычислении позиции.
     * @default 88px
     * */
    minHeight?: number;
}
